#include <stdio.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    for(int tc=0; tc<T; ++tc){
        int n,m; scanf("%d %d",&n,&m);
        long long total=1LL*n*m;
        if(total%2){
            printf("-1\n");
        }else{
            for(int i=0;i<n;++i){
                for(int j=0;j<m;++j){
                    if(j) printf(" ");
                    printf("1");
                }
                printf("\n");
            }
        }
        if(tc!=T-1) printf("\n");
    }
    return 0;
}

